import { isNonEmptyRange } from './type-guards.js';
import {
  defaultLabelFormatterStrategy,
  formatValueRange,
} from './value-formatters.js';
import type { HeaderData } from '../../../types.js';
import type { HeaderValueFormatter } from '../types/header.js';

export const getNonGeometryHeader = (
  value: HeaderData,
): HeaderValueFormatter => {
  if (isNonEmptyRange(value)) {
    return formatValueRange;
  }

  return defaultLabelFormatterStrategy;
};
